// convert a call line to an object
function toObject(str)
{
    var items = str.split("*");

    var data = {};
    data.Type = items[0].trim();
    for(var i = 1; i < items.length; i += 2)
        data[items[i]] = items[i+1];


    // reformat the date and time fields
    if(data.hasOwnProperty("DATE"))
        data.DATE = data.DATE.slice(2,4) + "-" + data.DATE.slice(0,2) + "-" + data.DATE.slice(4);
    if(data.hasOwnProperty("TIME"))
        data.TIME = data.TIME.slice(0,2) + ":" + data.TIME.slice(2);

    return data;
}

function isOneOf(itms)
{
    for(var i = 0; i < itms.length; ++i)
        if( msg.payload.startsWith(itms[i]) === true)
            return true;
    return false;
}

